(window.webpackJsonp=window.webpackJsonp||[]).push([[48],{330:function(v,_,p){"use strict";p.r(_);var t=p(14),a=Object(t.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("h1",{attrs:{id:"徘徊在云海千寻"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#徘徊在云海千寻"}},[v._v("#")]),v._v(" 徘徊在云海千寻")]),v._v(" "),_("h2",{attrs:{id:"当城市渐渐淹没"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#当城市渐渐淹没"}},[v._v("#")]),v._v(" 当城市渐渐淹没")]),v._v(" "),_("p",[v._v("开了一个河滩地的挑战图，大洪水会滚滚而来，淹没城市，毁灭一切，坚持240周则挑战成功。")]),v._v(" "),_("p",[v._v("挑战本身并没有什么特色，大概就是疯狂刷人口，在每个阶段洪水完全涨上来之前点开右侧海拔稍高的图，然后把城市扩展过去就行。开到第三张图就有山地了，洪水上涨速度大幅减缓，基本上就能过去了。")]),v._v(" "),_("p",[v._v("为了赶速度，城区基本上都是土路，建筑也是完全的格子城。挑战结束之后，也很难进一步转型升级，最终就只能眼看财政渐渐亏空，眼看大水分割城市，眼看一切都归于一无所有。")]),v._v(" "),_("p",[v._v("有时候觉得人生也是如此，前二十年努力拼搏赶速度，终于获得了一片高地，不那么容易被洪水淹没。但是在高地上的城市依然是从前的破落风格，无法转型升级，最终只能眼看他起高楼，眼看他楼塌了...却毫无办法。虽然领导说拿自己的名声来保证我能活到下个合同，但是这次他保住了，下次呢？或者下次之后的下次呢？")]),v._v(" "),_("p",[v._v("唉...")]),v._v(" "),_("p",[v._v("上周上班摸鱼的时候跟群友讨论哪一天不工作了该怎么办，打算找个风景不错生活成本不高的地方搞个创业公司写写小游戏啥的。最好是地方政府有创业补贴房租补贴什么的就更好了，反正创业并不为了挣钱，主要是填填简历空白，以及尽量少花点。")]),v._v(" "),_("p",[v._v("如果真想创业的话，花自己的钱显然是不合适的，怎么也得骗点投资人的钱。但是拿了投资人的钱，投资人就会像老板一样来搞监工，就不能摸鱼自由自在，甚至还不如打工了。世界是一个巨大的打工。")]),v._v(" "),_("p",[v._v("或者也可以开个小店什么的，找个海边民宿，背靠沙滩，做做烧烤，做做桌游。当然做点小生意也不妨碍开公司，只不过地点不用另找罢了。法人得找个不怕背债的挂上，毕竟谁知道哪天公司就爆雷了。给自己弄个CTO之类的角色，出去简历也好看点。")]),v._v(" "),_("p",[v._v("可惜班还是得上，想都是空想。")]),v._v(" "),_("h2",{attrs:{id:"摄像是心情的艺术"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#摄像是心情的艺术"}},[v._v("#")]),v._v(" 摄像是心情的艺术")]),v._v(" "),_("p",[v._v("翻相册看以前拍的果冻海")]),v._v(" "),_("p",[v._v("看以前拍的日落 拍的晚霞")]),v._v(" "),_("p",[v._v("忽然发现现在拍不出当时的这种感觉")]),v._v(" "),_("p",[v._v("可能并不完全是风景或者心态的问题")]),v._v(" "),_("p",[v._v("小米的色泽确实鲜艳 苹果的调色确实好看")]),v._v(" "),_("p",[v._v("而华为拍出来的就不会有特别惊艳的感觉")]),v._v(" "),_("p",[v._v("......")]),v._v(" "),_("br"),v._v(" "),_("p",[v._v("看着照片里情侣看落日 江边拍婚纱")]),v._v(" "),_("p",[v._v("或者只是单纯的jk 经常感觉很羡慕")]),v._v(" "),_("p",[v._v("可真让我找个对象 那好像又太难了")]),v._v(" "),_("p",[v._v("相比之下")]),v._v(" "),_("p",[v._v("还是看看爬坡心率194这种问题怎么解决")]),v._v(" "),_("p",[v._v("来的更实在一点")]),v._v(" "),_("p",[v._v("......")]),v._v(" "),_("br"),v._v(" "),_("p",[v._v("太阳底下走路的人是不会需要月光的")]),v._v(" "),_("p",[v._v("而下水道里走路的人是看不见月光的")]),v._v(" "),_("p",[v._v("大约 相遇就是为了 一起跨月山海 乘云远航")]),v._v(" "),_("p",[v._v("直到有一天  能一起看到岁月的尽头吧")]),v._v(" "),_("h2",{attrs:{id:"_24岁-是工程师a"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#_24岁-是工程师a"}},[v._v("#")]),v._v(" 24岁，是工程师A")]),v._v(" "),_("p",[v._v("非常平淡但是精神状态格外糟糕的一年过去了。")]),v._v(" "),_("p",[v._v("今年做了少许改善身体状况的尝试，但是基本上都是半途而废告终。除了拔了一颗智齿(严格来说是两颗)，并没有达成任何有意义的结果。体检报告大概率会变得更难看，但是也无所谓。工作上没有任何成果，但是在各种地方挂名倒是挂了一大堆。级别从垃圾堆提升到了垃圾桶，考评难度变大了，摆烂也变得更难了。考试考了五次没过，每次都差那么一丁点，考的我自己都开始怀疑人生了。")]),v._v(" "),_("p",[v._v("与他人沟通也逐渐变得困难，无论是家里人、同事、以前的朋友，还是关系更近或更远的人。社恐程度比之前又略微加深了一点，不想认识新的朋友，也不想和老的朋友过多接触。对感情从平和到抗拒，却又衍生出极微弱的期待。但仅仅也只是微弱的期待罢了，毕竟历史经验表明，有的梦想成真的概率并不高于太阳从西边出来。何况是连我自己都觉得不会有什么希望的开始。")]),v._v(" "),_("p",[v._v("游戏依然在打，原神铁道绝区零方舟雀魂王者吃鸡剑三都市天际线MC什么都沾点，包括大火的帕鲁也打了几个钟，但是电子ED本身还是相当的严重以致于没有一个游戏是坚持在玩的。管人依然在看，列表里关注的v似乎超过了五十个，但同样也没什么每天都会看的，大部分的v说实话都没啥活，一直直播打游戏看的下去的真的神人了。Mate60pro也陪了我一年了，走过了不少地方，拍了四千多张照片，也记录了各种各样的回忆。这对这一年的我来说，是最重要，并且应该也是唯一重要的内容了。")]),v._v(" "),_("p",[v._v("跟领导提了离开之后的一个月，日子大概是很潇洒的。成都九眼桥的繁华与喧嚣，蟠龙天地、牛首烟岚，无想水镇古韵悠然。苏州河畔静安光影，大悦城上冰火歌会。北外滩、嘉兴路，阳澄湖边小镰仓。如今已经一片废墟的深圳百草园，空中晃晃悠悠的比亚迪云轨。大鹏南澳湛蓝的海滨，英管岭俯瞰一切的淡然。还有奢华的岗头公寓，达到了住不起的水平。领导画不起饼，我也知道，所以也就一别两宽，没啥好说的。前方的路不好走，那我也没必要非得陪着去赴汤蹈火。")]),v._v(" "),_("p",[v._v("来到南京已经是深秋，而眼瞅着天气就渐渐变凉了。在夫子庙看着一场雨从夏天下到了秋天，看桠溪菊花渐开，汤山枫叶渐红。体育公园日暮时金色的秋景，莫愁湖边印染了各色的层林。天色微亮迈入栖霞山门，日出的光影照在红枫之上。午后的天平山则是喧闹与清幽并存，最终归于光福石壁禅寺的金黄梧桐与院外太湖的一池碧水。终于，冬天到来，一场大雪让南京变回了金陵。")]),v._v(" "),_("p",[v._v("时光渐渐迈入一年的结尾，从人烟稀疏的浦口象山湖到人山人海的外滩，23年以上海而始，也以上海而终。走过新年第一天的上研所、嘉兴路，开始2024新的一年。镇江西津渡、武进太湖湾、无锡南长街、江阴中山公园，以及有些年没去凑过热闹的秦淮灯会。南京又下了一场雪，而农历新年也适时而至。")]),v._v(" "),_("p",[v._v("二月的杭州西溪刚有了一点春的气息，而南国的港珠澳却已经是春意盎然。从澳门南角的黑沙沙滩到西侧的妈阁庙，从珠海最西边的斗门金台寺到最东边的港珠澳大桥人工岛。从香港岛最南的海怡半岛到西北的深圳湾口岸，从深圳宝安、蛇口到深圳湾、莲花山，处处花团锦簇、人潮如织，共同织就出新年南国的丰饶景象。")]),v._v(" "),_("p",[v._v("江南三月的主题必然是花。溧水遇园与雨花台梅岗盛开的梅花、不期而至的雪花、顾村南研花神大道以及鸡鸣寺珍珠河的樱花、常熟郊外高淳桠溪还有省农科院的油菜花、乌龙潭以及宜兴阳羡盛开的桃花。到处都是春意盎然，到处都是花开满山，但都比不上那映在我脑海里似有似无若隐若现的，似若惊鸿一瞥。")]),v._v(" "),_("p",[v._v("池黄高铁开通了，南京到黄山的距离近了那么一点。躺在新港国际的大草坪上，暖暖的晒着太阳，什么也不用担忧，确然是一种享受。上半年最大的假期来了，从湖州太湖古镇出发向东，沿着南太湖一路到七都，然后过震泽，到乌镇。去常州逛西太湖揽月湾，与太湖湾音乐节不期而遇，日落下的摩天轮带动全场气氛，直到深夜依然狂欢。越过长江去往巢湖中庙，苦海无边，回头是岸。曾经的骆岗机场，小杨哥的电音节如火如荼，一阵强劲的音乐响起，哦，原来是到金边园的老木屋了。")]),v._v(" "),_("p",[v._v("春天终究短暂，而夏天随即悄然而至。五月中旬的西安已然高达三十六度，昆明池到诗经里，创新港到咸阳城，清晨的广仁寺，陕历博与大雁塔。所谓所求皆所倾，所倾皆所得，大约是我今年最想要的祝福了。烟雨之中的九溪烟树，浙大玉泉校区的主席像，给五月一个最好的结尾。夏天是江与海的季节，看过鱼嘴的日落，去连岛寻觅一份海的蔚蓝。百家湖，虎丘湿地，北太湖，石臼湖，高邮湖，金鸡湖。在渔港村换个角度看太湖，依然湛蓝，依然唯美。石臼湖大桥的水上列车，日落时分，如画卷般美好。夜色下从琼姬墩到李公堤，远处的东方之门，璀璨而夺目。")]),v._v(" "),_("p",[v._v("梅雨季节的绍兴，风里似乎都有些黄酒气。仓桥直街到鲁迅故里，尽是古朴的江南韵味。浅浅路过一下毗卢寺，进行一个浅浅的拜。无所相求，求也不得。深中通道开通了，大湾区东西有了一条新的风景线；松木岭园区要启用了，精致之中不失几分荒凉。沿着松山湖逛到溪村，还是溪村更显奢华。坐上快艇从盐田直达南澳，海浪掀起波涛，将视线变得模糊。我依然喜欢这里，过去，现在，以及未来。七月中旬的BW是二次元的盛会，却也是社恐的火葬场。I人还是喜欢没有人的地方，比如川沙古镇，比如滴水湖。")]),v._v(" "),_("p",[v._v("从张家港的常阴沙过通沙汽渡去往北岸的南通，再坐上大巴回到南岸的苏州。苏通大桥下的老航母依然搁浅着，一个月后的大火将会把它付之一炬。苏州的探索度终于达成了100%，它足够的大，让我念念不忘，也许将来的将来，我还是会选择在苏州度过余生。在五马渡误打误撞坐上了长江邮轮，看见长江最精彩的日落月出。走过玄武湖的荷花栈道，看太阳渐渐消失在水里。南京也挺好，虽然给不了我自己什么留下来的理由，但就这样凑合着，也不是不行。")]),v._v(" "),_("p",[v._v("今年的夏天格外的热，四十度的天气延续了很多天。从四十度的宣城雁翅到四十度的芜宣机场，坐上八十九座的CRJ600小飞机飞往三十四度的舟山普陀山。在长峙岛坐上日落下的浪漫摩天轮，骑着小电驴感受大海的风。顶着漫天的大雾骑车在机动车道飞驰，然后去嵊泗岛看海浪拍打沙滩。等了一个夏天的的世纪晚霞在江心洲终于得到了一次满足，太阳落入江水，云映漫天霞光。青浦基地也快到投入使用的时候了，然而附近的风景与半年前没啥不同。大约大家届时面对的，就是这样一座乡间小城吧。")]),v._v(" "),_("p",[v._v("杭温高铁穿过浙南的山山水水，带入东海之滨的雁荡仙境。蓝天白云与大雨倾盆交汇于山间，绘出一道靓丽的七色彩虹。斯人若彩虹，遇上方知有，我相信一见钟情，但一见钟情的故事大约很难修成正果。你喜欢的大概率不是那个仅仅一面之缘而并不熟悉的人，而是一个以她为原型而脑补出来的影子。这样一个幻想中的人，现实中真的有可能存在吗？")]),v._v(" "),_("p",[v._v("如果说三年前在深圳，我对爱情的态度还是有所期许，尽力而为，如今的我对感情的态度已经流于幻想和迷梦。工作让我并不需要进行多少社交上的连接，多年前认识的朋友也已随着时光而渐渐散去。确实，单身也并没有什么不好，仅仅是脆弱和emo的时候，需要一个排解的方向。但没有谁会愿意做另一个人的情绪垃圾桶的，一味的单方面付出谁也做不到。情绪价值为负的人不配获得任何形式的爱情，除了对金钱的爱情，可我的余额支撑不起。")])])}),[],!1,null,null,null);_.default=a.exports}}]);